import{_ as a,o as n,c as p,aj as t}from"./chunks/framework.DNJ2HNkG.js";const _=JSON.parse('{"title":"Debian安装BCM94352驱动","description":"","frontmatter":{"title":"Debian安装BCM94352驱动","date":"2016-06-10T20:13:33.000Z","category":"Linux","tags":["Linux","Debian","驱动"]},"headers":[],"relativePath":"posts/Debian安装BCM94352驱动.md","filePath":"posts/Debian安装BCM94352驱动.md","lastUpdated":1783008259000}'),e={name:"posts/Debian安装BCM94352驱动.md"};function l(i,s,c,o,b,r){return n(),p("div",null,[...s[0]||(s[0]=[t(`<p>现在AC盛行，用bgn的速度太慢的完全受不了，所以买的笔记本或者台式都会安一个AC的无线网卡，现在比较常见的有BCM94352和Intel 7260AC，我对比测过，BCM94352的性能比7260AC强一点点，所以我用的网卡基本都是BCM的,Win下还好，Linux下怎么处理？</p><p>Ubuntu下如果用图形界面，在设置的驱动支持里面，可以看到网卡驱动，可以直接安装，如果是字符终端呢？</p><p>一般只要不用图形界面，我是不会去浪费这个内存和硬盘的，虽然现在也不值钱，但浪费是可耻的~~</p><p>不要试图去编译源码，在新的系统上支持很烂，各种编译错误。直接apt安装就行：</p><p><strong>apt-get install broadcom-sta-dkms modprobe -r b44 b43 b43legacy ssb brcmsmac modprobe wl</strong></p><p>安装完成后还需要禁用内核自带的驱动模块：</p><p><strong>vi /etc/modprobe.d/broadcom-sta-dkms.conf</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>blacklist b43</span></span>
<span class="line"><span>blacklist b43legacy</span></span>
<span class="line"><span>blacklist b44</span></span>
<span class="line"><span>blacklist bcma</span></span>
<span class="line"><span>blacklist brcm80211</span></span>
<span class="line"><span>blacklist brcmsmac</span></span>
<span class="line"><span>blacklist ssb</span></span></code></pre></div><p>做完之后<code>reboot</code>就可以了~~</p>`,9)])])}const m=a(e,[["render",l]]);export{_ as __pageData,m as default};
